#include <stdio.h>

int main() {
    int a, b;
    scanf("%d %d", &a, &b);

    int start, end;
    if (a < b) {
        start = a;
        end = b;
    } else {
        start = b;
        end = a;
    }

    int sum = 0;
    for (int i = start; i <= end; i++) {
        if (i % 2 == 0) {
            sum += i;
        }
    }

    printf("%d\n", sum);

    return 0;
}

#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);

    int count = 0;
    for (int i = 1; i <= n; i++) {
        if (i % 3 == 0 || i % 5 == 0) {
            count++;
        }
    }

    printf("%d\n", count);

    return 0;
}

#include <stdio.h>

int main() {
    int correct_pin = 1234;
    int entered_pin;
    int attempts = 0;

    while (attempts < 3) {
        printf("Enter PIN: ");
        scanf("%d", &entered_pin);

        if (entered_pin == correct_pin) {
            printf("PIN accepted.\n");
            return 0; // Exit successfully
        } else {
            attempts++;
            if (attempts < 3) {
                printf("Incorrect PIN. Try again.\n");
            }
        }
    }

    printf("Account locked.\n"); // All 3 attempts failed

    return 0;
}

#include <stdio.h>

int main() {
    int num_students;
    scanf("%d", &num_students);

    int total_score = 0;
    for (int i = 1; i <= num_students; i++) {
        int score;
        scanf("%d", &score);
        total_score += score;

        printf("Student %d: ", i);
        if (score >= 60) {
            printf("Pass\n");
        } else {
            printf("Fail\n");
        }
    }

    double class_average = (double)total_score / num_students;
    printf("Class Average: %.2f\n", class_average);

    return 0;
}

#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);

    int sum = 0;
    int temp_n = n; // Use a temporary variable to modify

    if (temp_n == 0) { // Handle case for input 0
        sum = 0;
    } else {
        while (temp_n > 0) {
            int digit = temp_n % 10;
            sum += digit;
            temp_n /= 10;
        }
    }

    printf("%d\n", sum);

    return 0;
}

#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);

    int a = 0, b = 1;
    if (n >= 0) { // Fibonacci sequence typically starts with 0
        printf("%d", a);
    }
    if (n >= 1) { // Print 1 if N is 1 or greater
        printf(" %d", b);
    }

    int next_fib;
    while (1) {
        next_fib = a + b;
        if (next_fib > n) {
            break;
        }
        printf(" %d", next_fib);
        a = b;
        b = next_fib;
    }
    printf("\n");

    return 0;
}

#include <stdio.h>
#include <limits.h> // For INT_MIN

int main() {
    int n;
    scanf("%d", &n);

    int max_val = INT_MIN; // Initialize with the smallest possible integer value

    for (int i = 0; i < n; i++) {
        int current_num;
        scanf("%d", &current_num);
        if (current_num > max_val) {
            max_val = current_num;
        }
    }

    printf("%d\n", max_val);

    return 0;
}

#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);

    long long factorial = 1; // Use long long to prevent potential overflow for slightly larger N

    if (n < 0) {
        printf("Factorial is not defined for negative numbers.\n");
        return 1; // Indicate error
    } else if (n == 0) {
        factorial = 1;
    } else {
        for (int i = 1; i <= n; i++) {
            factorial *= i;
        }
    }

    printf("%lld\n", factorial);

    return 0;
}

#include <stdio.h>

int main() {
    int choice;

    while (1) { // Loop indefinitely until an exit condition is met
        printf("1. Greet\n");
        printf("2. Exit\n");
        printf("Enter your choice: ");
        scanf("%d", &choice);

        if (choice == 1) {
            printf("Hello!\n");
        } else if (choice == 2) {
            printf("Exiting program.\n");
            break; // Exit the loop and terminate the program
        } else {
            printf("Invalid choice. Please try again.\n");
        }
        printf("\n"); // Add a newline for better readability between menu prompts
    }

    return 0;
}

#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);

    int reversed_n = 0;
    int temp_n = n;

    if (temp_n == 0) { // Special case for input 0
        printf("0\n");
        return 0;
    }

    while (temp_n > 0) {
        int digit = temp_n % 10;
        reversed_n = reversed_n * 10 + digit;
        temp_n /= 10;
    }

    printf("%d\n", reversed_n);

    return 0;
}
